mapper.select:
SELECT n.title, c.contents, c.create_dt AS DATE
    FROM tbl_comment c
JOIN tbl_news n ON c.news_id = n.news_id
WHERE c.user_id = #{userId}
    ORDER BY create_dt DESC
LIMIT #{size} OFFSET #{offset}

SELECT reporter_id, subscription_date AS DATE
    FROM tbl_subscription
WHERE user_id = #{userId}
    ORDER BY subscription_date DESC
LIMIT #{size} OFFSET #{offset}
